const raw = $input.first().json;
const body = raw.body || raw;
const user_id = parseInt(body.user_id, 10) || 0;
const procedures = Array.isArray(body.procedures) ? body.procedures : [];
if (!user_id || procedures.length === 0) throw new Error('user_id and procedures array required');
return [{ json: { user_id, procedures } }];

const prev = $('Normalize Input').first().json;
const order_number = $('Generate Order Number').first().json.order_number;
const procs = prev.procedures;
const total_amount = procs.reduce((sum, p) => sum + (Number(p.price) || 0), 0);
const user_id = parseInt(prev.user_id, 10);
const pending_procedures = procs.map(p => ({ id: p.id, name: p.name || p.procedure_name, room: p.room || p.room_number, room_number: p.room_number || p.room, price: Number(p.price) || 0 }));
const pending_procedures_json = JSON.stringify(pending_procedures);
return [{ json: { order_number, user_id, total_amount, pending_procedures, pending_procedures_json } }];

const j = $input.first().json;
const order_number_esc = String(j.order_number).replace(/'/g, "''");
const user_id_num = Number(j.user_id);
const total_amount_num = Number(j.total_amount);
const json_esc = String(j.pending_procedures_json).replace(/'/g, "''");
const query = `INSERT INTO unpaid_orders (order_number, user_id, payment_status, total_amount, pending_procedures) VALUES ('${order_number_esc}', ${user_id_num}, 'unpaid', ${total_amount_num}, '${json_esc}'::jsonb) RETURNING *`;
return [{ json: { query } }];

const order = $('Create Unpaid Order').first().json;
const prep = $('Prepare Order').first().json;
const firstProc = (prep.pending_procedures || [])[0] || {};
return [{ json: {
  success: true,
  order: {
    id: order.id,
    order_number: order.order_number,
    user_id: order.user_id,
    payment_status: order.payment_status,
    total_amount: order.total_amount,
    procedure_name: firstProc.name,
    procedure_id: firstProc.id,
    room_number: firstProc.room || firstProc.room_number
  }
} }];
